"use client";

import { useEffect, useMemo, useState } from "react";
import { Eye, Trash2, Check, Printer, X } from "lucide-react";

type Row = {
  no: number;
  usulanId?: string;
  esl: string;
  jabatan: string;
  namaPktGolNrpNip: string;
  kondisi: string;
  calonPengisiJabatan: string;
  catatan: string;
  ket: string;
};

type BahanRapat = {
  id: string;
  tanggal: string; // yyyy-mm-dd
  materiRapat: string;
  rows: Row[];
  status: "draft" | "final";
  createdAt: string;
  updatedAt?: string;
};

const STORAGE_KEY_BAHAN_RAPAT = "bnn_bahan_rapat_v1";
const ROWS_PER_PAGE = 5;

function loadBahanRapat(): BahanRapat[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = localStorage.getItem(STORAGE_KEY_BAHAN_RAPAT);
    const data = raw ? (JSON.parse(raw) as BahanRapat[]) : [];
    return Array.isArray(data) ? data : [];
  } catch {
    return [];
  }
}
function saveBahanRapat(list: BahanRapat[]) {
  localStorage.setItem(STORAGE_KEY_BAHAN_RAPAT, JSON.stringify(list));
}

function fmtDate(iso: string) {
  if (!iso) return "-";
  const [y, m, d] = iso.split("-");
  if (!y || !m || !d) return iso;
  return `${d}/${m}/${y}`;
}

function chunkRows<T>(arr: T[], size: number) {
  const out: T[][] = [];
  for (let i = 0; i < arr.length; i += size) out.push(arr.slice(i, i + size));
  return out.length ? out : [[]];
}

export default function DaftarBahanRapatPage() {
  const [items, setItems] = useState<BahanRapat[]>([]);
  const [openId, setOpenId] = useState<string | null>(null);

  useEffect(() => {
    setItems(loadBahanRapat());
  }, []);

  const sorted = useMemo(() => {
    return [...items].sort((a, b) =>
      (b.createdAt || "").localeCompare(a.createdAt || "")
    );
  }, [items]);

  const active = useMemo(() => {
    if (!openId) return null;
    return items.find((x) => x.id === openId) ?? null;
  }, [openId, items]);

  function toggleFinal(id: string) {
    const next = items.map((x) => {
      if (x.id !== id) return x;
      const toFinal = x.status !== "final";
      return {
        ...x,
        status: toFinal ? "final" : "draft",
        updatedAt: new Date().toISOString(),
      };
    });
    setItems(next);
    saveBahanRapat(next);
  }

  function onDelete(id: string) {
    const ok = confirm("Yakin mau hapus bahan rapat ini?");
    if (!ok) return;
    const next = items.filter((x) => x.id !== id);
    setItems(next);
    saveBahanRapat(next);
    if (openId === id) setOpenId(null);
  }

  function onPrint() {
    window.print();
  }

  return (
    <div className="px-2 py-2">
      {/* CARD UTAMA */}
      <div className="mx-auto w-full max-w-[1100px] rounded-md bg-white shadow-[0_14px_40px_rgba(0,0,0,0.18)] ring-1 ring-black/5">
        <div className="p-10">
          <div className="flex items-start justify-between gap-6">
            <div className="text-[11px] font-semibold text-zinc-900">
              <div>BADAN NARKOTIKA NASIONAL</div>
              <div>REPUBLIK INDONESIA</div>
              <div className="mt-2 h-[2px] w-[190px] bg-zinc-700/70" />
            </div>

            <div className="flex-1 pt-2 text-center">
              <div className="text-sm font-bold tracking-wide text-zinc-900">
                DAFTAR BAHAN RAPAT
              </div>
            </div>

            <div className="w-[190px]" />
          </div>

          <div className="mt-8 overflow-x-auto">
            <table className="w-full border border-zinc-700 text-[12px] text-zinc-900">
              <thead>
                <tr className="bg-zinc-200/80">
                  <Th className="w-[60px] text-center">NO</Th>
                  <Th className="w-[80px] text-center">ESL</Th>
                  <Th className="w-[220px] text-center">JABATAN</Th>
                  <Th className="w-[280px] text-center">
                    NAMA/PKT/GOL <br /> NRP/NIP
                  </Th>
                  <Th className="w-[220px] text-center">KONDISI</Th>
                  <Th className="w-[220px] text-center">
                    CALON PENGISI JABATAN
                  </Th>
                  <Th className="w-[220px] text-center">CATATAN</Th>
                  <Th className="w-[150px] text-center">KET</Th>
                  <Th className="w-[120px] text-center">STATUS</Th>
                  <Th className="w-[120px] text-center">AKSI</Th>
                </tr>
              </thead>

              <tbody>
                {sorted.length === 0 ? (
                  <tr className="border-t border-zinc-700">
                    <Td colSpan={10} className="py-10 text-center text-zinc-500">
                      Belum ada data bahan rapat. Silakan buat dulu di menu “Buat
                      Bahan Rapat”.
                    </Td>
                  </tr>
                ) : (
                  sorted.map((doc, idx) => {
                    const first = doc.rows?.[0];
                    return (
                      <tr key={doc.id} className="border-t border-zinc-700">
                        <Td className="text-center">{idx + 1}.</Td>

                        <Td className="align-top">{first?.esl || "-"}</Td>
                        <Td className="align-top whitespace-pre-wrap">
                          {first?.jabatan || "-"}
                        </Td>
                        <Td className="align-top whitespace-pre-wrap">
                          {first?.namaPktGolNrpNip || "-"}
                        </Td>
                        <Td className="align-top whitespace-pre-wrap">
                          {first?.kondisi || "-"}
                        </Td>
                        <Td className="align-top whitespace-pre-wrap">
                          {first?.calonPengisiJabatan || "-"}
                        </Td>
                        <Td className="align-top whitespace-pre-wrap">
                          {first?.catatan || "-"}
                        </Td>
                        <Td className="align-top whitespace-pre-wrap">
                          {first?.ket || "-"}
                        </Td>

                        <Td className="text-center">
                          {doc.status === "final" ? (
                            <span className="inline-flex items-center rounded-md bg-emerald-50 px-2 py-1 text-[11px] font-bold text-emerald-700">
                              FINAL
                            </span>
                          ) : (
                            <button
                              type="button"
                              onClick={() => toggleFinal(doc.id)}
                              className="inline-flex items-center justify-center rounded-md border border-emerald-500/40 bg-white px-2 py-1 text-emerald-700 hover:bg-emerald-50"
                              title="Klik untuk ACC (Final)"
                            >
                              <Check size={18} />
                            </button>
                          )}
                        </Td>

                        <Td className="text-center">
                          <div className="flex items-center justify-center gap-2">
                            <button
                              type="button"
                              onClick={() => setOpenId(doc.id)}
                              className="inline-flex h-9 w-9 items-center justify-center rounded-md border border-[#123473]/40 bg-white text-[#123473] shadow-sm hover:bg-[#123473]/5 active:scale-[0.98]"
                              title="Lihat"
                            >
                              <Eye size={18} />
                            </button>

                            <button
                              type="button"
                              onClick={() => onDelete(doc.id)}
                              className="inline-flex h-9 w-9 items-center justify-center rounded-md border border-red-500/40 bg-white text-red-600 shadow-sm hover:bg-red-50 active:scale-[0.98]"
                              title="Hapus"
                            >
                              <Trash2 size={18} />
                            </button>
                          </div>
                        </Td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>

          <div className="mt-10 text-[10px] text-zinc-700">
            <div>Birp SDM Aparatur dan Organisasi</div>
            <div>Sekretariat Utama BNN 2026</div>
          </div>
        </div>
      </div>

      {/* MODAL PREVIEW */}
      {active && (
        <div id="print-area" className="fixed inset-0 z-[9999] bg-black/40 p-4">
          <div className="mx-auto flex h-full w-full max-w-[1400px] flex-col overflow-hidden rounded-lg bg-white shadow-xl ring-1 ring-black/10">
            {/* toolbar */}
            <div className="print:hidden flex items-center justify-between gap-3 border-b px-5 py-4">
              <div>
                <div className="text-sm font-bold text-zinc-900">
                  Preview (A4 Landscape) untuk PDF
                </div>
                <div className="mt-1 text-xs text-zinc-600">
                  Tanggal:{" "}
                  <b className="text-zinc-900">{fmtDate(active.tanggal)}</b> •
                  Status:{" "}
                  <b
                    className={
                      active.status === "final"
                        ? "text-emerald-700"
                        : "text-zinc-900"
                    }
                  >
                    {active.status.toUpperCase()}
                  </b>
                </div>
              </div>

              <div className="flex items-center gap-2">
                {active.status !== "final" ? (
                  <button
                    type="button"
                    onClick={() => toggleFinal(active.id)}
                    className="inline-flex items-center gap-2 rounded-md bg-emerald-600 px-3 py-2 text-xs font-semibold text-white hover:brightness-110"
                  >
                    <Check size={16} />
                    ACC (Final)
                  </button>
                ) : null}

                <button
                  type="button"
                  onClick={onPrint}
                  className="inline-flex items-center gap-2 rounded-md bg-[#123473] px-3 py-2 text-xs font-semibold text-white hover:brightness-110"
                >
                  <Printer size={16} />
                  Print / Save PDF
                </button>

                <button
                  type="button"
                  onClick={() => setOpenId(null)}
                  className="inline-flex items-center gap-2 rounded-md border border-zinc-300 bg-white px-3 py-2 text-xs font-semibold text-zinc-700 hover:bg-zinc-50"
                >
                  <X size={16} />
                  Tutup
                </button>
              </div>
            </div>

            <div className="flex-1 overflow-auto bg-zinc-100 p-6 print:bg-white print:p-0">
              <A4LandscapePages doc={active} />
            </div>
          </div>
        </div>
      )}

      {/* PRINT CSS: A4 LANDSCAPE + sizing fix */}
      <style jsx global>{`
        @media print {
          @page {
            size: A4 landscape;
            margin: 8mm;
          }

          body * {
            visibility: hidden;
          }
          #print-area,
          #print-area * {
            visibility: visible;
          }
          #print-area {
            position: fixed;
            inset: 0;
            background: white !important;
            padding: 0 !important;
          }

          .print\\:hidden {
            display: none !important;
          }

          /* A4 landscape page box: 297mm x 210mm */
          .a4l-page {
            width: 297mm;
            min-height: 210mm;
            margin: 0 auto;
            box-shadow: none !important;
            border: none !important;
            page-break-after: always;
          }
          .a4l-page:last-child {
            page-break-after: auto;
          }
        }
      `}</style>
    </div>
  );
}

/** ====== HALAMAN A4 LANDSCAPE ====== */
function A4LandscapePages({ doc }: { doc: BahanRapat }) {
  const pages = useMemo(
    () => chunkRows(doc.rows || [], ROWS_PER_PAGE),
    [doc.rows]
  );

  return (
    <div className="flex flex-col items-center gap-6 print:gap-0">
      {pages.map((rows, pageIndex) => {
        const startNo = pageIndex * ROWS_PER_PAGE + 1;

        return (
          <div
            key={pageIndex}
            className="a4l-page w-[297mm] min-h-[210mm] rounded-md border border-zinc-200 bg-white p-[8mm] shadow-sm print:rounded-none print:border-0 print:p-0"
          >
            {/* KOP + JUDUL */}
            <div className="flex items-start justify-between">
              <div className="text-[12px] font-semibold text-zinc-900">
                <div>BADAN NARKOTIKA NASIONAL</div>
                <div>REPUBLIK INDONESIA</div>
                <div className="mt-1 h-[2px] w-[210px] bg-zinc-900/70" />
              </div>

              <div className="flex-1 text-center">
                <div className="text-[13px] font-bold text-zinc-900">
                  MATERI RAPAT TIM PENILAI KINERJA
                </div>
                <div className="text-[13px] font-bold text-zinc-900">
                  MUTASI JABATAN ADMINISTRATOR DI LINGKUNGAN BADAN NARKOTIKA
                  NASIONAL
                </div>
                <div className="mt-1 text-[12px] font-semibold text-zinc-900">
                  Tanggal {fmtDate(doc.tanggal)}
                </div>
              </div>

              <div className="w-[210px]" />
            </div>

            {/* TABLE (dibuat lebih lega karena landscape) */}
            <div className="mt-4">
              <table className="w-full border border-zinc-800 text-[12px] text-zinc-900">
                <thead>
                  <tr className="bg-zinc-200">
                    <th className="border border-zinc-800 px-2 py-1 text-center w-[32px]">
                      NO
                    </th>
                    <th className="border border-zinc-800 px-2 py-1 text-center w-[55px]">
                      ESL
                    </th>
                    <th className="border border-zinc-800 px-2 py-1 text-center w-[260px]">
                      JABATAN
                    </th>
                    <th className="border border-zinc-800 px-2 py-1 text-center w-[260px]">
                      NAMA/PKT/GOL <br /> NRP/NIP
                    </th>
                    <th className="border border-zinc-800 px-2 py-1 text-center w-[150px]">
                      KONDISI
                    </th>
                    <th className="border border-zinc-800 px-2 py-1 text-center w-[280px]">
                      CALON PENGISI JABATAN
                    </th>
                    <th className="border border-zinc-800 px-2 py-1 text-center w-[180px]">
                      CATATAN
                    </th>
                    <th className="border border-zinc-800 px-2 py-1 text-center w-[170px]">
                      KET
                    </th>
                  </tr>
                </thead>

                <tbody>
                  {rows.length ? (
                    rows.map((r, i) => (
                      <tr key={`${pageIndex}-${r.no}-${i}`}>
                        <td className="border border-zinc-800 px-2 py-1 text-center align-top">
                          {startNo + i}.
                        </td>
                        <td className="border border-zinc-800 px-2 py-1 align-top">
                          {r.esl || "-"}
                        </td>
                        <td className="border border-zinc-800 px-2 py-1 align-top whitespace-pre-wrap">
                          {r.jabatan || "-"}
                        </td>
                        <td className="border border-zinc-800 px-2 py-1 align-top whitespace-pre-wrap">
                          {r.namaPktGolNrpNip || "-"}
                        </td>
                        <td className="border border-zinc-800 px-2 py-1 align-top whitespace-pre-wrap">
                          {r.kondisi || "-"}
                        </td>
                        <td className="border border-zinc-800 px-2 py-1 align-top whitespace-pre-wrap">
                          {r.calonPengisiJabatan || "-"}
                        </td>
                        <td className="border border-zinc-800 px-2 py-1 align-top whitespace-pre-wrap">
                          {r.catatan || "-"}
                        </td>
                        <td className="border border-zinc-800 px-2 py-1 align-top whitespace-pre-wrap">
                          {r.ket || "-"}
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td
                        colSpan={8}
                        className="border border-zinc-800 px-3 py-10 text-center text-zinc-500"
                      >
                        Tidak ada baris data.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>

            {/* footer kiri */}
            <div className="mt-3 text-[11px] text-zinc-800">
              <i>Biro SDM Aparatur dan Organisasi Sekretariat Utama BNN 2025</i>
            </div>

            {/* paraf/TTD */}
            <div className="mt-6 border-t border-zinc-600 pt-2">
              <div className="text-[11px] text-zinc-700">PARAF:</div>
              <div className="mt-2 grid grid-cols-5 gap-2 text-[11px] text-zinc-800">
                <ParafBox title="1. SESTAMA" />
                <ParafBox title="2. DEPUTI PENCEGAHAN" />
                <ParafBox title="3. PLT. IRTAMA" />
                <ParafBox title="4. PLT. IRWASRIKSUS" />
                <ParafBox title="5. PLT. KARO SDMA & ORG" />
              </div>
            </div>

            <div className="mt-2 text-right text-[11px] text-zinc-500">
              Halaman {pageIndex + 1} / {pages.length}
            </div>
          </div>
        );
      })}
    </div>
  );
}

function ParafBox({ title }: { title: string }) {
  return (
    <div className="border border-zinc-600 p-2">
      <div className="font-semibold">{title}</div>
      <div className="mt-6 border-b border-zinc-500" />
    </div>
  );
}

function Th({
  children,
  className = "",
}: {
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <th
      className={["border border-zinc-700 px-3 py-2 font-bold", className].join(
        " "
      )}
    >
      {children}
    </th>
  );
}

function Td({
  children,
  className = "",
  colSpan,
}: {
  children: React.ReactNode;
  className?: string;
  colSpan?: number;
}) {
  return (
    <td
      colSpan={colSpan}
      className={["border border-zinc-700 px-2 py-2", className].join(" ")}
    >
      {children}
    </td>
  );
}
